mapper.sql:
SELECT
ID,
INVOICE_ID,
STATEMENT_NO,
INVOICE_TYPE,
RATE_ITEM_CODE,
RATE_ITEM_NAME,
NUMBER_COUNT,
AMOUNT,
PIECE_AMOUNT,
TAX,
TAX_AMOUNT,
UNIT_CODE,
UNIT_NAME,
RATE_ID,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME,
UPDATE_BY,
UPDATE_BY_NAME,
UPDATE_TIME
FROM
T_FD_INVOICE_DETAIL


        and ID = #{id}


        and INVOICE_ID = #{invoiceId}


        and STATEMENT_NO = #{statementNo}


        and INVOICE_TYPE = #{invoiceType}


        and RATE_ITEM_CODE = #{rateItemCode}


        and RATE_ITEM_NAME = #{rateItemName}


        and NUMBER_COUNT = #{numberCount}


        and AMOUNT = #{amount}


        and TAX = #{tax}


        and TAX_AMOUNT = #{taxAmount}

mapper.insert:
INSERT INTO T_FD_INVOICE_DETAIL( ID, INVOICE_ID, STATEMENT_NO, STATEMENT_DETAIL_ID, "TYPE", RATE_ITEM_CODE, RATE_ITEM_NAME, NUMBER_COUNT, NUMBER_COUNT2, PIECE_AMOUNT, AMOUNT, TAX, TAX_AMOUNT, UNIT_CODE, UNIT_NAME, RATE_ID, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, CARGO_INFO_ID, SHIPVOYAGE_ID, SHIPVOYAGE_ITEM_ID, SCN, SHIP_NAME, VOYAGE, TRADE_TYPE, IMP_EXP ) (
SELECT #{item.id, jdbcType=BIGINT}, #{item.invoiceId, jdbcType=BIGINT}, #{item.statementNo, jdbcType=VARCHAR}, #{item.statementDetailId, jdbcType=BIGINT}, #{item.type, jdbcType=VARCHAR}, #{item.rateItemCode, jdbcType=VARCHAR}, #{item.rateItemName, jdbcType=VARCHAR}, #{item.numberCount, jdbcType=DECIMAL}, #{item.numberCount2, jdbcType=DECIMAL}, #{item.pieceAmount, jdbcType=DECIMAL}, #{item.amount, jdbcType=DECIMAL}, #{item.tax, jdbcType=DECIMAL}, #{item.taxAmount, jdbcType=DECIMAL}, #{item.unitCode, jdbcType=VARCHAR}, #{item.unitName, jdbcType=VARCHAR}, #{item.rateId, jdbcType=BIGINT}, #{item.loginUserId, jdbcType=BIGINT}, #{item.loginUserName, jdbcType=VARCHAR}, #{item.now,jdbcType=TIMESTAMP}, #{item.cargoInfoId,jdbcType=BIGINT}, #{item.shipvoyageId,jdbcType=BIGINT}, #{item.shipvoyageItemId,jdbcType=BIGINT}, #{item.scn,jdbcType=VARCHAR}, #{item.shipName,jdbcType=VARCHAR}, #{item.voyage,jdbcType=VARCHAR}, #{item.tradeType,jdbcType=VARCHAR}, #{item.impExp,jdbcType=VARCHAR} FROM DUAL
)

mapper.select:
SELECT TFID.ID, TFID.INVOICE_ID, TFID.STATEMENT_NO, TFID.STATEMENT_DETAIL_ID, TFID."TYPE", TFID.RATE_ITEM_CODE, TFID.NUMBER_COUNT, TFID.NUMBER_COUNT2, TFID.AMOUNT, TFID.PIECE_AMOUNT, TFID.TAX, TFID.TAX_AMOUNT, TFID.UNIT_CODE, TFID.UNIT_NAME, TFID.RATE_ID, TFID.CREATE_BY, TFID.CREATE_BY_NAME, TFID.CREATE_TIME, TFID.UPDATE_BY, TFID.UPDATE_BY_NAME, TFID.UPDATE_TIME, TFID.SCN, CONCAT(CONCAT(TFID.SHIP_NAME,'_'),TFID.VOYAGE) "shipNameVoyage", CASE WHEN CONCAT(TBR.RATE_ITEM_NAME,DECODE(TBR.PROCESS_NAME,NULL,'','('||TBR.PROCESS_NAME||')')) IS NULL THEN TFID.RATE_ITEM_NAME ELSE CONCAT(TBR.RATE_ITEM_NAME,DECODE(TBR.PROCESS_NAME,NULL,'','('||TBR.PROCESS_NAME||')')) END RATE_ITEM_NAME
FROM T_FD_INVOICE_DETAIL TFID LEFT JOIN T_BUS_RATE TBR ON TFID.RATE_ID = TBR.ID
and TFID.INVOICE_ID = #{invoiceId}

SELECT distinct PRODUCT_CODE "productCode" FROM M_FEE_ITEM mfi
WHERE ITEM_CD = (
    SELECT rate_item_code  FROM T_BUS_RATE WHERE id = #{id}
)
